import os
import subprocess
import shlex
import sys

def create_backup(directory, format):
    if not os.path.isdir(directory):
        print("Invalid directory path.")
        return

    base_name = os.path.basename(os.path.normpath(directory))
    backup_name = f"{base_name}_backup.{format}"
    
    try:
        if format == 'tar.gz':
            command = f"tar -czf {shlex.quote(backup_name)} {shlex.quote(directory)}"
        elif format == 'tar.bz2':
            command = f"tar -cjf {shlex.quote(backup_name)} {shlex.quote(directory)}"
        elif format == 'zip':
            command = f"zip -r {shlex.quote(backup_name)} {shlex.quote(directory)}"
        elif format == '7z':
            command = f"7z a {shlex.quote(backup_name)} {shlex.quote(directory)}"
        else:
            print("Unsupported format. Use tar.gz, tar.bz2, zip, or 7z.")
            return

        subprocess.run(command, shell=True, check=True)
        print(f"Backup created successfully: {backup_name}")
    except subprocess.CalledProcessError as e:
        print(f"Error creating backup: {e}")

if __name__ == "__main__":
    if len(sys.argv) != 3:
        print("Usage: python backup_script.py <directory_path> <format>")
        sys.exit(1)

    dir_path = sys.argv[1]
    backup_format = sys.argv[2]
    create_backup(dir_path, backup_format)